SELECT 
  (SELECT COUNT(DISTINCT source_code) FROM data_sources) AS total_data_sources,
  (SELECT COUNT(DISTINCT metric_code) FROM metrics) AS total_metrics;

SELECT DISTINCT sub_region_name 
FROM sub_regions 
WHERE population > 10000000;

SELECT metric_name
FROM metrics
WHERE global_best_male = (
  SELECT MAX(global_best_male)
  FROM metrics
);

SELECT country_name, population
FROM countries
WHERE region = 'Americas' AND population > 50000000;
